mapper.select:
SELECT name
FROM member
WHERE member_id = #{loginUserId}

SELECT room_id, building, room_number, capacity
FROM lecture_room
WHERE building = #{building}

SELECT l.lecture_id AS lectureId, l.type AS lectureType, mj.name AS majorName, l.name AS lectureName, m.name AS proName, l.credit, ls.day_of_week AS dayOfWeek, ls.end_period AS endPeriod, ls.start_period AS startPeriod, lr.building, lr.room_number AS roomNumber, l.academic_year AS academicYear, l.status FROM lecture l LEFT JOIN member m ON l.member_id = m.member_id LEFT JOIN major mj ON l.major_id = mj.major_id LEFT JOIN lecture_schedule ls ON l.lecture_id = ls.lecture_id LEFT JOIN lecture_room lr ON ls.room_id = lr.room_id
AND l.member_id = #{loginUserId}
ORDER BY l.lecture_id DESC

mapper.update:
UPDATE lecture
SET status = #{status}
WHERE lecture_id = #{lectureId}
